/* Before (broken): */
ssize_t n = recv(fd, buf, len, 0);
if (n < 0) return -1;  /* EINTR treated as error! */

/* After (fixed): */
ssize_t n;
do { n = recv(fd, buf, len, 0); } while (n < 0 && errno == EINTR);
if (n < 0) return -1;

// Instead of separate stores:
// DB_STORE: HashMap<u64, Connection>
// STMT_STORE: HashMap<u64, Statement<'??>>

// Use raw pointers:
struct DbEntry {
    _conn: Connection,  // keeps sqlite3* alive
    raw: *mut rusqlite::ffi::sqlite3,
}
struct StmtEntry {
    raw: *mut rusqlite::ffi::sqlite3_stmt,
    db_handle: u64,
}
